parameters.jsCode:
// ============================================================
// CONFIG — this is the ONLY node you edit to adapt the pipeline
// to a different industry. Set your vertical, your 5 topics,
// and the posting cycle. Everything downstream is data-driven.
// ============================================================
const config = {
  brand: 'Your Brand',
  vertical: 'your niche or industry',              // <-- your industry / niche
  brandVoice: 'technical but accessible, enthusiastic, community-driven',
  llmModel: 'claude-haiku-4-5-20251001',

  // Image generation (KIE.ai)
  kieModel: 'nano-banana-2',
  kieAspectRatio: '1:1',
  kieResolution: '2K',
  kieOutputFormat: 'jpg',
  maxPollAttempts: 30,
  pollIntervalSeconds: 5,

  // Destinations — fill these in
  telegramChatId: 'YOUR_TELEGRAM_CHAT_ID',
  airtableBaseId: 'YOUR_AIRTABLE_BASE_ID',
  airtableTableId: 'YOUR_AIRTABLE_TABLE_ID',
  metaPageId: 'YOUR_META_PAGE_ID',
  metaIgUserId: 'YOUR_META_IG_USER_ID',

  // Hashtags added to every post (topic hashtags are appended per post)
  baseHashtags: '#yourbrand #yourindustry',

  // ---- Your 5 content topics ----
  // label:     shown in Airtable's "Type" field and used in the prompt
  // angle:     the editorial instruction for this topic
  // subtopics: the model rotates through these for variety
  // hashtags:  appended to baseHashtags for this topic
  topics: {
    t1: {
      label: 'Models',
      angle: 'Showcase notable creations and inspiring examples in this space.',
      subtopics: ['functional pieces', 'artistic pieces', 'practical builds', 'standout designs'],
      hashtags: '#showcase #inspiration'
    },
    t2: {
      label: 'Tips',
      angle: 'Give one actionable, specific tip that helps people improve.',
      subtopics: ['getting started', 'common mistakes', 'quality improvements', 'time savers'],
      hashtags: '#tips #howto'
    },
    t3: {
      label: 'Deep Dive',
      angle: 'Explain one technical topic in real depth for an advanced audience.',
      subtopics: ['fundamentals', 'advanced techniques', 'troubleshooting', 'the science behind it'],
      hashtags: '#deepdive #technical'
    },
    t4: {
      label: 'Process',
      angle: 'Walk through part of the creation or design process.',
      subtopics: ['ideation', 'iteration', 'tools and workflow', 'from concept to finished'],
      hashtags: '#process #behindthescenes'
    },
    t5: {
      label: 'Art',
      angle: 'Celebrate the creative and artistic side of this space.',
      subtopics: ['abstract work', 'creative experiments', 'standout aesthetics', 'unexpected ideas'],
      hashtags: '#art #creative'
    }
  },

  // 12-slot posting cycle (an Instagram grid of 4 rows x 3). Reference the
  // topic keys above. Change the mix to whatever suits your channel.
  cycle: ['t1', 't1', 't1', 't2', 't3', 't2', 't5', 't5', 't5', 't4', 't4', 't4']
};

// Advance the cycle position based on the last logged post
const records = $input.first().json.records || [];
let lastPosition = -1;
if (records.length > 0 && records[0].fields && records[0].fields['Cycle Position'] != null) {
  lastPosition = parseInt(records[0].fields['Cycle Position'], 10);
}
const position = (lastPosition + 1) % config.cycle.length;

config.contentType = config.cycle[position];                       // slot key, e.g. 't1'
config.contentLabel = (config.topics[config.contentType] || {}).label || config.contentType;
config.cyclePosition = position;
config.cycleRow = Math.floor(position / 3);
config.runTimestamp = new Date().toISOString();

return [{ json: config }];

// Build the topic-dedup context AND the generation prompt from the selected
// topic. All industry-specific wording comes from the Config node's topics.
const records = $input.first().json.records || [];
const config = $('Config').first().json;
const topic = config.topics[config.contentType] || {};

const pastTopics = records.map(function (r) {
  const title = r.fields['Content Title'] || '';
  const prompt = (r.fields['Image Prompt'] || '').substring(0, 120);
  return '- ' + title + ' (prompt: ' + prompt + '...)';
}).join('\n') || 'No previous posts found — this is the first post of this type.';

const subtopics = (topic.subtopics || []).join(', ');
const allHashtags = [config.baseHashtags, topic.hashtags].filter(Boolean).join(' ');

const system = 'You are a social content creator for ' + config.brand +
  ', working in the ' + config.vertical + ' space. Your voice is ' + config.brandVoice +
  '. You create content that educates and inspires this audience.';

const userPrompt =
  'Generate a "' + topic.label + '" post about ' + config.vertical + '.\n' +
  'Angle: ' + topic.angle + '\n' +
  'Rotate through these subtopics for variety: ' + subtopics + '. Pick whichever is most useful and timely.\n\n' +
  'Respond with EXACTLY this JSON (no markdown, no extra text):\n' +
  '{\n' +
  '  "subtopic": "the specific subtopic you chose",\n' +
  '  "title": "short catchy title (max 8 words)",\n' +
  '  "caption": "an Instagram caption, 2-3 short paragraphs, ends with a question to engage followers, and includes these hashtags: ' + allHashtags + '",\n' +
  '  "imagePrompt": "a text-to-image prompt for a striking, professional photo illustrating this post (2-4 sentences describing subject, lighting, and composition; no text in the image)",\n' +
  '  "voiceoverScript": "a 15-25 second voiceover script, conversational and energetic, starts with a hook"\n' +
  '}\n\n' +
  'IMPORTANT — do NOT repeat any of these recent posts:\n' +
  pastTopics + '\n\n' +
  'Generate fresh, unique content on a subtopic not listed above.';

return [{ json: Object.assign({}, config, { pastTopics: pastTopics, system: system, userPrompt: userPrompt }) }];

// Parse the AI response and standardize the output for the shared publish
// pipeline. Forwards the config fields the downstream nodes need.
const response = $input.first().json;
const config = $('Config').first().json;

let parsed;
try {
  let content = response.content[0].text;
  content = content.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
  parsed = JSON.parse(content);
} catch (e) {
  throw new Error('Failed to parse AI response: ' + e.message);
}

return [{
  json: {
    contentType: config.contentType,
    contentLabel: config.contentLabel,
    contentSubtype: parsed.subtopic || config.contentLabel,
    postTitle: parsed.title || config.contentLabel,
    caption: parsed.caption || '',
    imagePrompt: parsed.imagePrompt || ('Professional photo illustrating ' + config.vertical + ', clean composition, natural light'),
    elevenLabsScript: parsed.voiceoverScript || '',
    // forward config fields the downstream pipeline needs
    brand: config.brand,
    kieModel: config.kieModel,
    kieAspectRatio: config.kieAspectRatio,
    kieResolution: config.kieResolution,
    kieOutputFormat: config.kieOutputFormat,
    maxPollAttempts: config.maxPollAttempts,
    telegramChatId: config.telegramChatId,
    airtableBaseId: config.airtableBaseId,
    airtableTableId: config.airtableTableId,
    metaPageId: config.metaPageId,
    metaIgUserId: config.metaIgUserId,
    runTimestamp: config.runTimestamp
  }
}];

const item = $input.first().json;
const state = item.data?.state || 'pending';
const taskId = $('KIE Create').first().json.data?.taskId || '';
const pollCount = (item._pollCount || 0) + 1;
// Standardized content + config comes from Parse Content
const cfg = $('Parse Content').first().json;
if (state === 'success') {
  let imageUrl = '';
  try {
    const resultJson = JSON.parse(item.data.resultJson);
    imageUrl = resultJson.resultUrls?.[0] || '';
  } catch (e) { imageUrl = 'PARSE_ERROR: ' + e.message; }
  return [{ json: { ...cfg, generatedImageUrl: imageUrl, taskId, kieState: 'success', _pollCount: pollCount } }];
} else if (state === 'fail' || pollCount >= 30) {
  return [{ json: { ...cfg, taskId, kieState: 'fail', _pollCount: pollCount,
    reason: state === 'fail' ? 'KIE task failed' : 'Max polls (' + pollCount + ') reached' } }];
} else {
  return [{ json: { ...item, ...cfg, taskId, kieState: 'polling', _pollCount: pollCount } }];
}

